module top (
    input clk,
    input [1:0] select,
    output reg [1:0] result
);
always @(posedge clk) begin
    case (select)
        2'b00: result <= 2'b11;
        2'b01: result <= 2'b10;
        2'b10: result <= 2'b01;
        default: result <= 2'b00;
    endcase
end
endmodule

p_result.next =
	(eq_uu<1>(p_select, value<2>{0x2u})
		? value<2>{0x1u}
		: (eq_uu<1>(p_select, value<2>{0x1u}) ? value<2>{0x2u} : (logic_not<1>(p_select) ? value<2>{0x3u} : value<2>{0u})));
